'use client';

import { useState } from 'react';
import { Search, Mail, Phone, UserCheck, Eye, Plus, GraduationCap } from 'lucide-react';
import Link from 'next/link';
import { UserProfile } from '@/lib/types/users_turmas';

interface ProfessoresListProps {
    professores: UserProfile[];
}

export function ProfessoresList({ professores }: ProfessoresListProps) {
    const [searchTerm, setSearchTerm] = useState('');

    const filteredProfs = professores.filter(prof => {
        const matchesSearch = (prof.full_name?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
            (prof.email?.toLowerCase() || '').includes(searchTerm.toLowerCase());
        return matchesSearch;
    });

    return (
        <div className="space-y-6">
            {/* Toolbar */}
            <div className="flex flex-col sm:flex-row gap-4 justify-between bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                <div className="relative flex-1 max-w-lg">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
                    <input
                        type="text"
                        placeholder="Buscar professor por nome ou email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-gray-200 focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition-all"
                    />
                </div>
            </div>

            {/* Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProfs.length > 0 ? (
                    filteredProfs.map((prof) => (
                        <div key={prof.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition-shadow group">
                            <div className="h-24 bg-gradient-to-r from-gray-800 to-gray-700 relative">
                                <div className="absolute -bottom-10 left-1/2 -translate-x-1/2">
                                    <div className="w-20 h-20 rounded-full border-4 border-white shadow-sm overflow-hidden bg-white flex items-center justify-center text-xl font-bold text-gray-700">
                                        {prof.avatar_url ? (
                                            <img src={prof.avatar_url} alt={prof.full_name} className="w-full h-full object-cover" />
                                        ) : (
                                            prof.full_name?.charAt(0) || 'P'
                                        )}
                                    </div>
                                </div>
                            </div>

                            <div className="pt-12 pb-6 px-6 text-center">
                                <h3 className="text-lg font-bold text-gray-900 mb-1">{prof.full_name || 'Nome não definido'}</h3>
                                <div className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-red-50 text-red-700 text-xs font-medium mb-4">
                                    <GraduationCap size={14} />
                                    Professor
                                </div>

                                <div className="space-y-2 text-sm text-gray-600 text-left bg-gray-50/50 p-3 rounded-xl border border-gray-100">
                                    <div className="flex items-center gap-2">
                                        <Mail className="w-4 h-4 text-gray-400" />
                                        <span className="truncate">{prof.email}</span>
                                    </div>
                                    {prof.telefone && (
                                        <div className="flex items-center gap-2">
                                            <Phone className="w-4 h-4 text-gray-400" />
                                            <span>{prof.telefone}</span>
                                        </div>
                                    )}
                                </div>

                                <Link
                                    href={`/admin/professores/${prof.id}`}
                                    className="mt-6 block w-full py-2.5 bg-gray-900 text-white rounded-xl font-medium hover:bg-black transition-colors shadow-lg shadow-gray-200"
                                >
                                    Ver Perfil
                                </Link>
                            </div>
                        </div>
                    ))
                ) : (
                    <div className="col-span-full py-16 text-center text-gray-400 bg-white rounded-2xl border border-dashed border-gray-200">
                        <UserCheck className="w-12 h-12 mx-auto text-gray-300 mb-3" />
                        <p className="font-medium">Nenhum professor encontrado.</p>
                        <p className="text-sm">Tente buscar por outro termo.</p>
                    </div>
                )}
            </div>

            <div className="flex justify-between items-center text-sm text-gray-500 px-2">
                <span>Total de {professores.length} professores</span>
            </div>
        </div>
    );
}
